#include<iostream>
#include<cstdio>
#include<algorithm>
using namespace std;
class Solution {
 public:
  int countTrailingZeros(int n) {
    int count = 0;
    while(n) {
      n >>= 1;
      ++count;
    }
    return count;
  }
};
